import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum CommissionStatus {
  QUEUE = 'Queue',
  SKETCH = 'Sketch',
  LINEART = 'Lineart',
  COLOR = 'Color',
  RENDER = 'Render',
  DONE = 'Done'
}

export interface Commission {
  id: string;
  clientName: string;
  contact?: string; // e.g., Discord handle or email (private in real app, shown here for admin)
  title: string;
  description: string;
  type: 'Headshot' | 'Bust' | 'Half Body' | 'Full Body' | 'Illustration';
  price: number;
  status: CommissionStatus;
  dateAdded: string;
  lastUpdated: string;
  thumbnailUrl?: string; // Optional reference image or WIP shot
  notes?: string; // Private notes for the artist
}

export type ThemeMode = 'client' | 'admin';

import { GoogleGenAI } from "@google/genai";
import { Commission } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY is not set in process.env");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const generateClientUpdate = async (commission: Commission): Promise<string> => {
  const ai = getAiClient();
  if (!ai) return "Error: API Key missing.";

  const prompt = `
    You are a professional and friendly freelance artist assistant.
    Write a short, polite email/message update for a client named "${commission.clientName}".

    Context:
    - Commission Title: ${commission.title}
    - Current Status: ${commission.status}
    - Type: ${commission.type}

    The tone should be excited but professional. Mention that the "${commission.status}" phase is going well.
    If the status is "Queue", thank them for their patience.
    If the status is "Done", tell them the files are ready for review.
    Keep it under 100 words.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Could not generate update.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Failed to generate update. Please try again later.";
  }
};

export const suggestWorkPlan = async (commission: Commission): Promise<string> => {
    const ai = getAiClient();
    if (!ai) return "Error: API Key missing.";

    const prompt = `
      I am a digital artist. I need a quick 3-step checklist to focus on for this commission:
      Type: ${commission.type}
      Description: ${commission.description}
      Current Stage: ${commission.status}

      Provide 3 concise, actionable bullet points to help me move to the next stage.
    `;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text || "Could not generate plan.";
    } catch (error) {
      console.error("Gemini Error:", error);
      return "Failed to generate plan.";
    }
  };

import React from 'react';
import { CommissionStatus } from '../types';
import { STATUS_STEPS } from '../constants';
import { Check, Circle } from 'lucide-react';

interface ProgressBarProps {
  currentStatus: CommissionStatus;
}

export const ProgressBar: React.FC<ProgressBarProps> = ({ currentStatus }) => {
  const currentIndex = STATUS_STEPS.indexOf(currentStatus);

  return (
    <div className="w-full mt-4">
      <div className="flex items-center justify-between relative">
        {/* Background Line */}
        <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 bg-slate-700 rounded-full -z-0"></div>

        {/* Active Line */}
        <div 
            className="absolute left-0 top-1/2 transform -translate-y-1/2 h-1 bg-indigo-500 rounded-full transition-all duration-500 -z-0"
            style={{ width: `${(currentIndex / (STATUS_STEPS.length - 1)) * 100}%` }}
        ></div>

        {STATUS_STEPS.map((step, index) => {
          const isCompleted = index <= currentIndex;
          const isCurrent = index === currentIndex;

          return (
            <div key={step} className="flex flex-col items-center relative z-10 group">
              <div 
                className={`
                  w-6 h-6 rounded-full flex items-center justify-center border-2 transition-all duration-300
                  ${isCompleted ? 'bg-indigo-600 border-indigo-600' : 'bg-slate-800 border-slate-600'}
                  ${isCurrent ? 'ring-4 ring-indigo-500/30 scale-110' : ''}
                `}
              >
                {isCompleted ? (
                   <Check size={14} className="text-white" />
                ) : (
                   <Circle size={8} className="text-slate-500 fill-slate-500" />
                )}
              </div>
              <span className={`
                absolute top-8 text-[10px] md:text-xs font-medium tracking-wide transition-colors duration-300 whitespace-nowrap
                ${isCurrent ? 'text-indigo-400' : isCompleted ? 'text-slate-400' : 'text-slate-600'}
              `}>
                {step}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Commission } from '../types';
import { generateClientUpdate, suggestWorkPlan } from '../services/geminiService';
import { Wand2, Send, ListTodo, X } from 'lucide-react';

interface AdminToolsProps {
  commission: Commission;
  onClose: () => void;
}

export const AdminTools: React.FC<AdminToolsProps> = ({ commission, onClose }) => {
  const [generatedText, setGeneratedText] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'email' | 'plan'>('email');

  const handleGenerate = async () => {
    setLoading(true);
    setGeneratedText('');
    let result = '';

    if (activeTab === 'email') {
      result = await generateClientUpdate(commission);
    } else {
      result = await suggestWorkPlan(commission);
    }

    setGeneratedText(result);
    setLoading(false);
  };

  return (
    <div className="mt-4 bg-slate-900/50 p-4 rounded-lg border border-slate-700 relative animate-in fade-in slide-in-from-top-4">
      <button 
        onClick={onClose} 
        className="absolute top-2 right-2 text-slate-500 hover:text-white"
      >
        <X size={16} />
      </button>

      <div className="flex gap-2 mb-4">
        <button
          onClick={() => setActiveTab('email')}
          className={`flex items-center gap-2 px-3 py-1.5 rounded text-sm transition-colors ${
            activeTab === 'email' ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'
          }`}
        >
          <Send size={14} /> Draft Update
        </button>
        <button
          onClick={() => setActiveTab('plan')}
          className={`flex items-center gap-2 px-3 py-1.5 rounded text-sm transition-colors ${
            activeTab === 'plan' ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'
          }`}
        >
          <ListTodo size={14} /> Work Checklist
        </button>
      </div>

      <div className="min-h-[100px] bg-slate-950 rounded p-3 text-slate-300 text-sm whitespace-pre-wrap border border-slate-800 font-mono">
        {loading ? (
            <div className="flex items-center gap-2 text-indigo-400">
                <Wand2 className="animate-spin" size={16} /> Generating AI suggestion...
            </div>
        ) : generatedText ? (
            generatedText
        ) : (
            <span className="text-slate-600 italic">Click generate to use Gemini AI...</span>
        )}
      </div>

      <div className="mt-3 flex justify-end">
        <button
            onClick={handleGenerate}
            disabled={loading}
            className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white rounded-md text-sm font-medium transition-all disabled:opacity-50"
        >
            <Wand2 size={16} /> {loading ? 'Thinking...' : 'Generate'}
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Commission, CommissionStatus } from '../types';
import { ProgressBar } from './ProgressBar';
import { STATUS_STEPS } from '../constants';
import { AdminTools } from './AdminTools';
import { 
  Edit2, 
  Trash2, 
  ChevronRight, 
  ChevronLeft, 
  Calendar, 
  DollarSign, 
  Sparkles 
} from 'lucide-react';

interface CommissionCardProps {
  commission: Commission;
  isAdmin: boolean;
  onUpdateStatus: (id: string, newStatus: CommissionStatus) => void;
  onDelete: (id: string) => void;
}

export const CommissionCard: React.FC<CommissionCardProps> = ({ 
  commission, 
  isAdmin, 
  onUpdateStatus,
  onDelete 
}) => {
  const [showAdminTools, setShowAdminTools] = useState(false);

  const getStatusColor = (status: CommissionStatus) => {
    switch(status) {
      case CommissionStatus.QUEUE: return 'bg-slate-600';
      case CommissionStatus.SKETCH: return 'bg-blue-600';
      case CommissionStatus.LINEART: return 'bg-cyan-600';
      case CommissionStatus.COLOR: return 'bg-purple-600';
      case CommissionStatus.RENDER: return 'bg-indigo-600';
      case CommissionStatus.DONE: return 'bg-emerald-600';
      default: return 'bg-slate-600';
    }
  };

  const handleNextStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex < STATUS_STEPS.length - 1) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex + 1]);
    }
  };

  const handlePrevStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex > 0) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex - 1]);
    }
  };

  return (
    <div className="bg-slate-800/50 backdrop-blur-md border border-slate-700 rounded-xl p-6 shadow-xl hover:shadow-2xl transition-all duration-300 group">
      <div className="flex flex-col md:flex-row gap-6">
        {/* Image / Thumbnail Section */}
        <div className="w-full md:w-1/4">
          <div className="aspect-square rounded-lg overflow-hidden bg-slate-900 border border-slate-700 relative">
             {commission.thumbnailUrl ? (
                <img 
                    src={commission.thumbnailUrl} 
                    alt={commission.title} 
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                />
             ) : (
                <div className="w-full h-full flex items-center justify-center text-slate-600">
                    <span className="text-4xl">?</span>
                </div>
             )}
             <div className={`absolute top-2 left-2 px-2 py-1 rounded text-xs font-bold text-white shadow-lg ${getStatusColor(commission.status)}`}>
                 {commission.status}
             </div>
          </div>
        </div>

        {/* Details Section */}
        <div className="w-full md:w-3/4 flex flex-col justify-between">
          <div>
            <div className="flex justify-between items-start">
              <div>
                <h3 className="text-xl font-bold text-slate-100">{commission.title}</h3>
                <p className="text-indigo-400 text-sm font-medium mb-2">@{commission.clientName}</p>
              </div>
              {isAdmin && (
                <div className="flex gap-2">
                   <button 
                     onClick={() => setShowAdminTools(!showAdminTools)}
                     className="p-2 text-slate-400 hover:text-indigo-400 hover:bg-slate-700/50 rounded-lg transition-colors"
                     title="AI Tools"
                   >
                     <Sparkles size={18} />
                   </button>
                   <button 
                     onClick={() => onDelete(commission.id)}
                     className="p-2 text-slate-400 hover:text-red-400 hover:bg-slate-700/50 rounded-lg transition-colors"
                   >
                     <Trash2 size={18} />
                   </button>
                </div>
              )}
            </div>

            <p className="text-slate-400 text-sm leading-relaxed mb-4">
              {commission.description}
            </p>

            <div className="flex flex-wrap gap-4 text-xs text-slate-500 font-mono mb-4">
              <span className="flex items-center gap-1 bg-slate-900/50 px-2 py-1 rounded">
                <Calendar size={12} /> {commission.dateAdded}
              </span>
              <span className="flex items-center gap-1 bg-slate-900/50 px-2 py-1 rounded">
                <DollarSign size={12} /> {commission.price}
              </span>
              <span className="bg-slate-900/50 px-2 py-1 rounded border border-slate-700 text-indigo-300">
                 {commission.type}
              </span>
            </div>
          </div>

          <div className="mt-2">
            <ProgressBar currentStatus={commission.status} />

            {isAdmin && (
              <div className="flex justify-end gap-2 mt-4 pt-4 border-t border-slate-700/50">
                 <button 
                   onClick={handlePrevStep}
                   disabled={commission.status === CommissionStatus.QUEUE}
                   className="flex items-center gap-1 px-3 py-1 text-xs font-medium text-slate-400 hover:text-white disabled:opacity-30 hover:bg-slate-700 rounded transition-colors"
                 >
                   <ChevronLeft size={14} /> Prev Step
                 </button>
                 <button 
                   onClick={handleNextStep}
                   disabled={commission.status === CommissionStatus.DONE}
                   className="flex items-center gap-1 px-3 py-1 text-xs font-medium bg-indigo-600 hover:bg-indigo-500 text-white rounded transition-colors disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-indigo-500/20"
                 >
                   Next Step <ChevronRight size={14} />
                 </button>
              </div>
            )}
          </div>
        </div>
      </div>

      {isAdmin && showAdminTools && (
         <AdminTools commission={commission} onClose={() => setShowAdminTools(false)} />
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Commission, CommissionStatus } from '../types';
import { Plus, X } from 'lucide-react';

interface AddCommissionFormProps {
  onAdd: (c: Commission) => void;
  onCancel: () => void;
}

export const AddCommissionForm: React.FC<AddCommissionFormProps> = ({ onAdd, onCancel }) => {
  const [formData, setFormData] = useState<Partial<Commission>>({
    clientName: '',
    title: '',
    description: '',
    type: 'Full Body',
    price: 0,
    status: CommissionStatus.QUEUE,
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newCommission: Commission = {
      id: `c-${Date.now()}`,
      clientName: formData.clientName || 'Anonymous',
      title: formData.title || 'Untitled',
      description: formData.description || '',
      type: formData.type as any,
      price: Number(formData.price),
      status: formData.status as CommissionStatus,
      dateAdded: new Date().toISOString().split('T')[0],
      lastUpdated: new Date().toISOString().split('T')[0],
      // Use a random placeholder for demo purposes
      thumbnailUrl: `https://picsum.photos/400/400?random=${Date.now()}`
