  return (
    <div className="bg-slate-800 border border-slate-700 rounded-xl p-6 mb-8 animate-in fade-in zoom-in-95 duration-200">
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-lg font-bold text-white flex items-center gap-2">
            <Plus size={20} className="text-indigo-400"/> New Commission
        </h3>
        <button onClick={onCancel} className="text-slate-400 hover:text-white">
            <X size={20} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="space-y-4">
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">Client Name</label>
            <input 
              required
              type="text" 
              className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
              value={formData.clientName}
              onChange={e => setFormData({...formData, clientName: e.target.value})}
              placeholder="e.g. ArtLover99"
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">Commission Title</label>
            <input 
              required
              type="text" 
              className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
              placeholder="e.g. Warrior Character Sheet"
            />
          </div>
           <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">Type</label>
            <select 
              className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
              value={formData.type}
              onChange={e => setFormData({...formData, type: e.target.value as any})}
            >
                <option value="Headshot">Headshot</option>
                <option value="Bust">Bust</option>
                <option value="Half Body">Half Body</option>
                <option value="Full Body">Full Body</option>
                <option value="Illustration">Illustration</option>
            </select>
          </div>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">Price ($)</label>
            <input 
              type="number" 
              className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
