              onChange={e => setFormData({...formData, price: Number(e.target.value)})}
            />
          </div>
           <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">Initial Status</label>
            <select 
              className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
