import React, { useState, useEffect, useMemo } from 'react';
import { Commission, CommissionStatus, ThemeMode } from './types';
import { MOCK_COMMISSIONS } from './constants';
import { CommissionCard } from './components/CommissionCard';
import { AddCommissionForm } from './components/AddCommissionForm';
import { Search, Palette, Shield, User, LayoutGrid, List } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [commissions, setCommissions] = useState<Commission[]>([]);
  const [viewMode, setViewMode] = useState<ThemeMode>('client');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<CommissionStatus | 'All'>('All');
  const [isAdding, setIsAdding] = useState(false);

  // Initialize Data
  useEffect(() => {
    // In a real app, fetch from API. Here we simulate localStorage or fallback to mocks.
    const stored = localStorage.getItem('arttrack_commissions');
    if (stored) {
      setCommissions(JSON.parse(stored));
    } else {
      setCommissions(MOCK_COMMISSIONS);
      localStorage.setItem('arttrack_commissions', JSON.stringify(MOCK_COMMISSIONS));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Persistence
  useEffect(() => {
    if (commissions.length > 0) {
      localStorage.setItem('arttrack_commissions', JSON.stringify(commissions));
    }
  }, [commissions]);

  // Handlers
  const handleUpdateStatus = (id: string, newStatus: CommissionStatus) => {
    setCommissions(prev => prev.map(c => 
      c.id === id ? { ...c, status: newStatus, lastUpdated: new Date().toISOString().split('T')[0] } : c
    ));
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Are you sure you want to delete this commission?')) {
      setCommissions(prev => prev.filter(c => c.id !== id));
    }
  };

  const handleAdd = (newCommission: Commission) => {
    setCommissions(prev => [newCommission, ...prev]);
    setIsAdding(false);
  };

  // Filter Logic
  const filteredCommissions = useMemo(() => {
    return commissions.filter(c => {
      const matchesSearch = 
        c.clientName.toLowerCase().includes(searchTerm.toLowerCase()) || 
        c.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.id.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesFilter = statusFilter === 'All' || c.status === statusFilter;

      return matchesSearch && matchesFilter;
    });
  }, [commissions, searchTerm, statusFilter]);

  // Statistics
  const stats = useMemo(() => {
    return {
        queue: commissions.filter(c => c.status === CommissionStatus.QUEUE).length,
        active: commissions.filter(c => c.status !== CommissionStatus.QUEUE && c.status !== CommissionStatus.DONE).length,
        done: commissions.filter(c => c.status === CommissionStatus.DONE).length
    }
  }, [commissions]);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 selection:bg-indigo-500/30">

      {/* Header */}
      <header className="fixed top-0 w-full z-50 bg-slate-950/80 backdrop-blur-md border-b border-slate-800">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center text-white font-bold">
                A
            </div>
            <h1 className="text-xl font-bold tracking-tight text-white hidden sm:block">
                ArtTrack <span className="text-indigo-500">.</span>
            </h1>
          </div>

          <div className="flex items-center gap-4">
            {/* View Mode Toggle */}
            <div className="flex bg-slate-900 rounded-lg p-1 border border-slate-800">
               <button 
                onClick={() => setViewMode('client')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-medium transition-all ${viewMode === 'client' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
               >
                 <User size={14} /> <span className="hidden sm:inline">Client View</span>
               </button>
               <button 
                onClick={() => setViewMode('admin')}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-medium transition-all ${viewMode === 'admin' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
               >
                 <Shield size={14} /> <span className="hidden sm:inline">Artist Admin</span>
               </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="pt-24 pb-20 px-4 max-w-6xl mx-auto">

        {/* Intro / Stats */}
        <div className="mb-10 text-center sm:text-left sm:flex justify-between items-end border-b border-slate-800 pb-8">
            <div>
                <h2 className="text-3xl font-bold text-white mb-2">
                    {viewMode === 'client' ? 'Commission Status Board' : 'Artist Dashboard'}
                </h2>
                <p className="text-slate-400 max-w-lg">
                    {viewMode === 'client' 
                        ? 'Track the real-time progress of your requested artwork. Search by your name or ID below.' 
                        : 'Manage your queue, update statuses, and draft client messages with AI assistance.'}
                </p>
            </div>
            <div className="flex gap-4 mt-6 sm:mt-0 text-sm">
                <div className="bg-slate-900 border border-slate-800 px-4 py-2 rounded-lg text-center min-w-[80px]">
