                ))
            )}
        </div>

      </main>

      {/* Simple Footer */}
      <footer className="border-t border-slate-800 py-8 text-center text-slate-600 text-sm">
        <p>© {new Date().getFullYear()} ArtTrack Dashboard. Designed for artists & clients.</p>
      </footer>
    </div>
  );
};

