import React, { useState } from 'react';
import { Commission, CommissionStatus } from '../types';
import { ProgressBar } from './ProgressBar';
import { STATUS_STEPS } from '../constants';
import { AdminTools } from './AdminTools';
import { 
  Trash2, 
  ChevronRight, 
  ChevronLeft, 
  Calendar, 
  DollarSign, 
  Sparkles 
} from 'lucide-react';

interface CommissionCardProps {
  commission: Commission;
  isAdmin: boolean;
  onUpdateStatus: (id: string, newStatus: CommissionStatus) => void;
  onDelete: (id: string) => void;
}

export const CommissionCard: React.FC<CommissionCardProps> = ({ 
  commission, 
  isAdmin, 
  onUpdateStatus,
  onDelete 
}) => {
  const [showAdminTools, setShowAdminTools] = useState(false);

  const getStatusColor = (status: CommissionStatus) => {
    switch(status) {
      case CommissionStatus.QUEUE: return 'bg-slate-600';
      case CommissionStatus.SKETCH: return 'bg-blue-600';
      case CommissionStatus.LINEART: return 'bg-cyan-600';
      case CommissionStatus.COLOR: return 'bg-purple-600';
      case CommissionStatus.RENDER: return 'bg-indigo-600';
      case CommissionStatus.DONE: return 'bg-emerald-600';
      default: return 'bg-slate-600';
    }
  };

  const handleNextStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex < STATUS_STEPS.length - 1) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex + 1]);
    }
  };

  const handlePrevStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex > 0) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex - 1]);
    }
  };

  return (
    <div className="bg-slate-800/50 backdrop-blur-md border border-slate-700 rounded-xl p-6 shadow-xl hover:shadow-2xl transition-all duration-300 group">
      <div className="flex flex-col md:flex-row gap-6">
        {/* Image / Thumbnail Section */}
        <div className="w-full md:w-1/4">
          <div className="aspect-square rounded-lg overflow-hidden bg-slate-900 border border-slate-700 relative">
             {commission.thumbnailUrl ? (
                <img 
                    src={commission.thumbnailUrl} 
                    alt={commission.title} 
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                />
             ) : (
                <div className="w-full h-full flex items-center justify-center text-slate-600">
                    <span className="text-4xl">?</span>
                </div>
             )}
             <div className={`absolute top-2 left-2 px-2 py-1 rounded text-xs font-bold text-white shadow-lg ${getStatusColor(commission.status)}`}>
                 {commission.status}
             </div>
          </div>
        </div>

        {/* Details Section */}
        <div className="w-full md:w-3/4 flex flex-col justify-between">
          <div>
            <div className="flex justify-between items-start">
              <div>
                <h3 className="text-xl font-bold text-slate-100">{commission.title}</h3>
                <p className="text-indigo-400 text-sm font-medium mb-2">@{commission.clientName}</p>
              </div>
              {isAdmin && (
                <div className="flex gap-2">
                   <button 
                     onClick={() => setShowAdminTools(!showAdminTools)}
                     className="p-2 text-slate-400 hover:text-indigo-400 hover:bg-slate-700/50 rounded-lg transition-colors"
                     title="AI 小幫手"
                   >
                     <Sparkles size={18} />
                   </button>
                   <button 
                     onClick={() => onDelete(commission.id)}
                     className="p-2 text-slate-400 hover:text-red-400 hover:bg-slate-700/50 rounded-lg transition-colors"
                     title="刪除"
                   >
                     <Trash2 size={18} />
                   </button>
                </div>
              )}
            </div>

            <p className="text-slate-400 text-sm leading-relaxed mb-4">
              {commission.description}
            </p>

            <div className="flex flex-wrap gap-4 text-xs text-slate-500 font-mono mb-4">
              <span className="flex items-center gap-1 bg-slate-900/50 px-2 py-1 rounded">
                <Calendar size={12} /> {commission.dateAdded}
              </span>
              <span className="flex items-center gap-1 bg-slate-900/50 px-2 py-1 rounded">
                <DollarSign size={12} /> {commission.price}
              </span>
              <span className="bg-slate-900/50 px-2 py-1 rounded border border-slate-700 text-indigo-300">
                 {commission.type}
              </span>
            </div>
          </div>

          <div className="mt-2">
            <ProgressBar currentStatus={commission.status} />

            {isAdmin && (
              <div className="flex justify-end gap-2 mt-4 pt-4 border-t border-slate-700/50">
                 <button 
                   onClick={handlePrevStep}
                   disabled={commission.status === CommissionStatus.QUEUE}
                   className="flex items-center gap-1 px-3 py-1 text-xs font-medium text-slate-400 hover:text-white disabled:opacity-30 hover:bg-slate-700 rounded transition-colors"
                 >
                   <ChevronLeft size={14} /> 上一步
                 </button>
                 <button 
                   onClick={handleNextStep}
                   disabled={commission.status === CommissionStatus.DONE}
                   className="flex items-center gap-1 px-3 py-1 text-xs font-medium bg-indigo-600 hover:bg-indigo-500 text-white rounded transition-colors disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-indigo-500/20"
                 >
                   下一步 <ChevronRight size={14} />
                 </button>
              </div>
            )}
          </div>
        </div>
      </div>

      {isAdmin && showAdminTools && (
         <AdminTools commission={commission} onClose={() => setShowAdminTools(false)} />
      )}
    </div>
  );
};

