import React, { useState } from 'react';
import { Commission, CommissionStatus } from '../types';
import { ProgressBar } from './ProgressBar';
import { STATUS_STEPS } from '../constants';
import { AdminTools } from './AdminTools';
import { 
  Trash2, 
  ChevronRight, 
  ChevronLeft, 
  Calendar, 
  DollarSign, 
  Sparkles 
} from 'lucide-react';

interface CommissionCardProps {
  commission: Commission;
  isAdmin: boolean;
  onUpdateStatus: (id: string, newStatus: CommissionStatus) => void;
  onDelete: (id: string) => void;
}

export const CommissionCard: React.FC<CommissionCardProps> = ({ 
  commission, 
  isAdmin, 
  onUpdateStatus,
  onDelete 
}) => {
  const [showAdminTools, setShowAdminTools] = useState(false);

  // Updated Status Colors for Light/Forest Theme
  const getStatusColor = (status: CommissionStatus) => {
    switch(status) {
      case CommissionStatus.QUEUE: return 'bg-stone-200 text-stone-700';
      case CommissionStatus.SKETCH: return 'bg-sky-100 text-sky-800 border-sky-200';
      case CommissionStatus.LINEART: return 'bg-cyan-100 text-cyan-800 border-cyan-200';
      case CommissionStatus.COLOR: return 'bg-purple-100 text-purple-800 border-purple-200';
      case CommissionStatus.RENDER: return 'bg-emerald-100 text-emerald-800 border-emerald-200';
      case CommissionStatus.DONE: return 'bg-[#1a472a] text-white border-[#1a472a]';
      default: return 'bg-stone-200 text-stone-700';
    }
  };

  const handleNextStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex < STATUS_STEPS.length - 1) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex + 1]);
    }
  };

  const handlePrevStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex > 0) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex - 1]);
    }
  };

  return (
    <div className="bg-white border border-stone-200 rounded-xl p-6 shadow-sm hover:shadow-md transition-all duration-300 group">

      {/* Details Only (No Image) */}
      <div className="flex flex-col justify-between">
        <div>
          <div className="flex justify-between items-start mb-2">
            <div>
              <div className="flex items-center gap-3 mb-1">
                  <span className={`px-2 py-0.5 rounded text-[10px] font-bold border ${getStatusColor(commission.status)}`}>
                    {commission.status}
                  </span>
                  <p className="text-[#1a472a] text-xs font-bold tracking-wide">@{commission.clientName}</p>
              </div>
              <h3 className="text-xl font-bold text-stone-800">{commission.title}</h3>
            </div>

            {isAdmin && (
              <div className="flex gap-2">
                  <button 
                    onClick={() => setShowAdminTools(!showAdminTools)}
                    className={`p-2 rounded-lg transition-colors ${showAdminTools ? 'bg-emerald-100 text-emerald-700' : 'text-stone-400 hover:text-emerald-600 hover:bg-emerald-50'}`}
                    title="AI 小幫手"
                  >
                    <Sparkles size={18} />
                  </button>
                  <button 
                    onClick={() => onDelete(commission.id)}
                    className="p-2 text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                    title="刪除"
                  >
                    <Trash2 size={18} />
                  </button>
              </div>
            )}
          </div>

          <p className="text-stone-600 text-sm leading-relaxed mb-4">
            {commission.description}
          </p>

          <div className="flex flex-wrap gap-4 text-xs text-stone-500 font-mono mb-4 border-t border-dashed border-stone-200 pt-4">
            <span className="flex items-center gap-1 bg-stone-100 px-2 py-1 rounded">
              <Calendar size={12} /> {commission.dateAdded}
            </span>
            <span className="flex items-center gap-1 bg-stone-100 px-2 py-1 rounded">
              <DollarSign size={12} /> {commission.price}
            </span>
            <span className="bg-stone-100 px-2 py-1 rounded border border-stone-200 text-[#1a472a]">
                {commission.type}
            </span>
          </div>
        </div>

        <div className="mt-2">
          <ProgressBar currentStatus={commission.status} />

          {isAdmin && (
            <div className="flex justify-end gap-2 mt-4 pt-4 border-t border-stone-100">
                <button 
                  onClick={handlePrevStep}
                  disabled={commission.status === CommissionStatus.QUEUE}
                  className="flex items-center gap-1 px-3 py-1.5 text-xs font-medium text-stone-500 hover:text-stone-800 disabled:opacity-30 hover:bg-stone-100 rounded transition-colors"
                >
                  <ChevronLeft size={14} /> 上一步
                </button>
                <button 
                  onClick={handleNextStep}
                  disabled={commission.status === CommissionStatus.DONE}
                  className="flex items-center gap-1 px-3 py-1.5 text-xs font-medium bg-[#1a472a] hover:bg-[#143620] text-white rounded transition-colors disabled:opacity-50 disabled:cursor-not-allowed shadow-sm"
                >
                  下一步 <ChevronRight size={14} />
                </button>
            </div>
          )}
        </div>
      </div>

      {isAdmin && showAdminTools && (
         <AdminTools commission={commission} onClose={() => setShowAdminTools(false)} />
      )}
    </div>
  );
};

import React from 'react';
import { CommissionStatus } from '../types';
import { STATUS_STEPS } from '../constants';
import { Check, Circle } from 'lucide-react';

interface ProgressBarProps {
  currentStatus: CommissionStatus;
}

export const ProgressBar: React.FC<ProgressBarProps> = ({ currentStatus }) => {
  const currentIndex = STATUS_STEPS.indexOf(currentStatus);

  return (
    <div className="w-full mt-4">
      <div className="flex items-center justify-between relative">
        {/* Background Line */}
        <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 bg-stone-200 rounded-full -z-0"></div>

        {/* Active Line (Forest Green) */}
        <div 
            className="absolute left-0 top-1/2 transform -translate-y-1/2 h-1 bg-[#1a472a] rounded-full transition-all duration-500 -z-0"
            style={{ width: `${(currentIndex / (STATUS_STEPS.length - 1)) * 100}%` }}
        ></div>

        {STATUS_STEPS.map((step, index) => {
          const isCompleted = index <= currentIndex;
          const isCurrent = index === currentIndex;

          return (
            <div key={step} className="flex flex-col items-center relative z-10 group">
              <div 
                className={`
                  w-6 h-6 rounded-full flex items-center justify-center border-2 transition-all duration-300
                  ${isCompleted ? 'bg-[#1a472a] border-[#1a472a]' : 'bg-white border-stone-300'}
                  ${isCurrent ? 'ring-4 ring-[#1a472a]/20 scale-110' : ''}
                `}
              >
                {isCompleted ? (
                   <Check size={14} className="text-white" />
                ) : (
                   <Circle size={8} className="text-stone-300 fill-stone-300" />
                )}
              </div>
              <span className={`
                absolute top-8 text-[10px] md:text-xs font-medium tracking-wide transition-colors duration-300 whitespace-nowrap
                ${isCurrent ? 'text-[#1a472a] font-bold' : isCompleted ? 'text-stone-500' : 'text-stone-400'}
              `}>
                {step}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

