import React, { useState } from 'react';
import { Commission } from '../types';
import { generateClientUpdate, suggestWorkPlan } from '../services/geminiService';
import { Wand2, Send, ListTodo, X } from 'lucide-react';

interface AdminToolsProps {
  commission: Commission;
  onClose: () => void;
}

export const AdminTools: React.FC<AdminToolsProps> = ({ commission, onClose }) => {
  const [generatedText, setGeneratedText] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'email' | 'plan'>('email');

  const handleGenerate = async () => {
    setLoading(true);
    setGeneratedText('');
    let result = '';

    if (activeTab === 'email') {
      result = await generateClientUpdate(commission);
    } else {
      result = await suggestWorkPlan(commission);
    }

    setGeneratedText(result);
    setLoading(false);
  };

  return (
    <div className="mt-4 bg-stone-50 p-4 rounded-lg border border-stone-200 relative animate-in fade-in slide-in-from-top-4">
      <button 
        onClick={onClose} 
        className="absolute top-2 right-2 text-stone-400 hover:text-stone-700"
      >
        <X size={16} />
      </button>

      <div className="flex gap-2 mb-4">
        <button
          onClick={() => setActiveTab('email')}
          className={`flex items-center gap-2 px-3 py-1.5 rounded text-sm transition-colors ${
            activeTab === 'email' ? 'bg-[#1a472a] text-white' : 'bg-stone-200 text-stone-600 hover:bg-stone-300'
          }`}
        >
          <Send size={14} /> 草擬回信
        </button>
        <button
          onClick={() => setActiveTab('plan')}
          className={`flex items-center gap-2 px-3 py-1.5 rounded text-sm transition-colors ${
            activeTab === 'plan' ? 'bg-[#1a472a] text-white' : 'bg-stone-200 text-stone-600 hover:bg-stone-300'
          }`}
        >
          <ListTodo size={14} /> 工作建議
        </button>
      </div>

      <div className="min-h-[100px] bg-white rounded p-3 text-stone-700 text-sm whitespace-pre-wrap border border-stone-300 font-mono shadow-inner">
        {loading ? (
            <div className="flex items-center gap-2 text-[#1a472a]">
                <Wand2 className="animate-spin" size={16} /> 正在生成 AI 建議...
            </div>
        ) : generatedText ? (
            generatedText
        ) : (
            <span className="text-stone-400 italic">點擊下方按鈕讓 Gemini AI 為您產生內容...</span>
        )}
      </div>

      <div className="mt-3 flex justify-end">
        <button
            onClick={handleGenerate}
            disabled={loading}
            className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-[#1a472a] to-emerald-700 hover:from-[#143620] hover:to-emerald-800 text-white rounded-md text-sm font-medium transition-all disabled:opacity-50 shadow-sm"
        >
            <Wand2 size={16} /> {loading ? '思考中...' : '生成內容'}
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Commission, CommissionStatus, ThemeMode } from './types';
import { MOCK_COMMISSIONS } from './constants';
import { CommissionCard } from './components/CommissionCard';
import { AddCommissionForm } from './components/AddCommissionForm';
import { Search, Palette, Shield, User } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [commissions, setCommissions] = useState<Commission[]>([]);
  const [viewMode, setViewMode] = useState<ThemeMode>('client');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<CommissionStatus | 'All'>('All');
  const [isAdding, setIsAdding] = useState(false);

  // Initialize Data
  useEffect(() => {
    const stored = localStorage.getItem('arttrack_commissions_zh_v1');
    if (stored) {
      setCommissions(JSON.parse(stored));
    } else {
      setCommissions(MOCK_COMMISSIONS);
      localStorage.setItem('arttrack_commissions_zh_v1', JSON.stringify(MOCK_COMMISSIONS));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Persistence
  useEffect(() => {
    if (commissions.length > 0) {
      localStorage.setItem('arttrack_commissions_zh_v1', JSON.stringify(commissions));
    }
  }, [commissions]);

  // Handlers
  const handleUpdateStatus = (id: string, newStatus: CommissionStatus) => {
    setCommissions(prev => prev.map(c => 
      c.id === id ? { ...c, status: newStatus, lastUpdated: new Date().toISOString().split('T')[0] } : c
    ));
  };

  const handleDelete = (id: string) => {
    if (window.confirm('確定要刪除此委託嗎？')) {
      setCommissions(prev => prev.filter(c => c.id !== id));
    }
  };

  const handleAdd = (newCommission: Commission) => {
    setCommissions(prev => [newCommission, ...prev]);
    setIsAdding(false);
  };

  // Filter Logic
  const filteredCommissions = useMemo(() => {
    return commissions.filter(c => {
      const matchesSearch = 
        c.clientName.toLowerCase().includes(searchTerm.toLowerCase()) || 
        c.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.id.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesFilter = statusFilter === 'All' || c.status === statusFilter;

      return matchesSearch && matchesFilter;
    });
  }, [commissions, searchTerm, statusFilter]);

  // Statistics
  const stats = useMemo(() => {
    return {
        queue: commissions.filter(c => c.status === CommissionStatus.QUEUE).length,
        active: commissions.filter(c => c.status !== CommissionStatus.QUEUE && c.status !== CommissionStatus.DONE).length,
        done: commissions.filter(c => c.status === CommissionStatus.DONE).length
    }
  }, [commissions]);

  return (
    <div className="min-h-screen bg-[#fbfaf8] text-stone-700 selection:bg-emerald-200">

      {/* Header - Rounded Bottom */}
      <header className="fixed top-0 w-full z-50 bg-[#1a472a] shadow-lg shadow-[#1a472a]/10 rounded-b-3xl border-b-4 border-[#143620]">
        <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-white/20 rounded-2xl flex items-center justify-center text-white font-bold border-2 border-white/30 text-xl transform rotate-3">
                A
            </div>
            <h1 className="text-2xl font-bold tracking-wide text-white hidden sm:block">
                ArtTrack <span className="text-emerald-300">.</span>
            </h1>
          </div>

          <div className="flex items-center gap-4">
            {/* View Mode Toggle - Capsule Style */}
            <div className="flex bg-[#11301c] rounded-full p-1.5 border border-[#2d5c40]">
               <button 
                onClick={() => setViewMode('client')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-bold transition-all ${viewMode === 'client' ? 'bg-[#fbfaf8] text-[#1a472a] shadow-md' : 'text-emerald-100/60 hover:text-white'}`}
               >
                 <User size={16} /> <span className="hidden sm:inline">委託人</span>
               </button>
               <button 
                onClick={() => setViewMode('admin')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-bold transition-all ${viewMode === 'admin' ? 'bg-[#fbfaf8] text-[#1a472a] shadow-md' : 'text-emerald-100/60 hover:text-white'}`}
               >
                 <Shield size={16} /> <span className="hidden sm:inline">繪師</span>
               </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="pt-32 pb-20 px-4 max-w-5xl mx-auto">

        {/* Intro / Stats */}
        <div className="mb-12 text-center sm:text-left sm:flex justify-between items-end">
            <div className="mb-6 sm:mb-0">
                <h2 className="text-3xl font-bold text-[#1a472a] mb-3 tracking-tight">
                    {viewMode === 'client' ? '委託進度一覽 ✨' : '繪師工作台 🎨'}
                </h2>
                <p className="text-stone-500 max-w-lg font-medium">
                    {viewMode === 'client' 
                        ? '歡迎回來！在下方輸入您的 ID 或暱稱，看看您的委託跑到哪了～' 
                        : '今天也要元氣滿滿的畫圖！這裡可以管理排單和進度喔。'}
                </p>
            </div>
            <div className="flex gap-3 justify-center sm:justify-end text-sm">
                <div className="bg-white border-2 border-stone-200 px-5 py-3 rounded-2xl text-center min-w-[90px] shadow-sm transform hover:-translate-y-1 transition-transform">
                    <div className="text-2xl font-bold text-stone-600">{stats.queue}</div>
                    <div className="text-xs text-stone-400 font-bold">排單中</div>
                </div>
                <div className="bg-white border-2 border-emerald-100 px-5 py-3 rounded-2xl text-center min-w-[90px] shadow-sm transform hover:-translate-y-1 transition-transform">
                    <div className="text-2xl font-bold text-emerald-600">{stats.active}</div>
                    <div className="text-xs text-emerald-600/70 font-bold">繪製中</div>
                </div>
                <div className="bg-white border-2 border-[#1a472a]/20 px-5 py-3 rounded-2xl text-center min-w-[90px] shadow-sm transform hover:-translate-y-1 transition-transform">
                    <div className="text-2xl font-bold text-[#1a472a]">{stats.done}</div>
                    <div className="text-xs text-[#1a472a]/70 font-bold">已完成</div>
                </div>
            </div>
        </div>

        {/* Controls - Floating & Rounded */}
        <div className="flex flex-col md:flex-row gap-4 mb-10 sticky top-24 z-40 bg-[#fbfaf8]/90 p-4 -mx-4 md:mx-0 rounded-3xl border-2 border-white shadow-lg shadow-stone-200/50 backdrop-blur-md">
          <div className="relative flex-grow">
            <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-stone-400" size={20} />
            <input 
              type="text" 
              placeholder="搜尋委託人名稱、項目或 ID..." 
              className="w-full bg-white border-2 border-stone-200 text-stone-700 pl-12 pr-6 py-3 rounded-full focus:ring-4 focus:ring-[#1a472a]/10 focus:border-[#1a472a] focus:outline-none transition-all placeholder:text-stone-400 font-medium"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex gap-3 overflow-x-auto pb-2 md:pb-0 hide-scrollbar px-1">
            <select 
                className="bg-white border-2 border-stone-200 text-stone-600 px-6 py-3 rounded-full focus:ring-4 focus:ring-[#1a472a]/10 focus:border-[#1a472a] focus:outline-none font-bold cursor-pointer hover:border-stone-300"
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value as any)}
            >
                <option value="All">所有狀態</option>
                {Object.values(CommissionStatus).map(s => (
                    <option key={s} value={s}>{s}</option>
                ))}
            </select>

            {viewMode === 'admin' && (
                <button 
                    onClick={() => setIsAdding(!isAdding)}
                    className="flex items-center gap-2 bg-[#1a472a] hover:bg-[#25613a] text-white px-6 py-3 rounded-full font-bold transition-all shadow-lg shadow-[#1a472a]/20 hover:shadow-xl hover:-translate-y-0.5 whitespace-nowrap active:scale-95"
                >
                    <Palette size={20} /> 新增委託
                </button>
            )}
          </div>
        </div>

        {/* Add Form */}
        {viewMode === 'admin' && isAdding && (
            <AddCommissionForm onAdd={handleAdd} onCancel={() => setIsAdding(false)} />
        )}

        {/* List */}
        <div className="space-y-6">
            {filteredCommissions.length === 0 ? (
                <div className="text-center py-24 bg-white rounded-3xl border-2 border-dashed border-stone-200">
                    <div className="mx-auto w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center mb-4">
                        <Search className="text-stone-400" size={32} />
                    </div>
                    <h3 className="text-xl font-bold text-stone-600">找不到相關委託捏...</h3>
                    <p className="text-stone-400 mt-2 font-medium">試試看別的關鍵字？</p>
                </div>
            ) : (
                filteredCommissions.map(commission => (
                    <CommissionCard 
                        key={commission.id}
                        commission={commission}
                        isAdmin={viewMode === 'admin'}
                        onUpdateStatus={handleUpdateStatus}
                        onDelete={handleDelete}
                    />
                ))
            )}
        </div>

      </main>

      {/* Footer */}
      <footer className="py-10 text-center text-stone-400 text-sm font-medium">
        <p>© {new Date().getFullYear()} ArtTrack Dashboard. Made with 💚 for Artists.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Commission, CommissionStatus } from '../types';
import { ProgressBar } from './ProgressBar';
import { STATUS_STEPS } from '../constants';
import { AdminTools } from './AdminTools';
import { 
  Trash2, 
  ChevronRight, 
  ChevronLeft, 
  Calendar, 
  DollarSign, 
  Sparkles 
} from 'lucide-react';

interface CommissionCardProps {
  commission: Commission;
  isAdmin: boolean;
  onUpdateStatus: (id: string, newStatus: CommissionStatus) => void;
  onDelete: (id: string) => void;
}

export const CommissionCard: React.FC<CommissionCardProps> = ({ 
  commission, 
  isAdmin, 
  onUpdateStatus,
  onDelete 
}) => {
  const [showAdminTools, setShowAdminTools] = useState(false);

  // Updated Status Colors for Cute Theme (Pill badges)
  const getStatusColor = (status: CommissionStatus) => {
    switch(status) {
      case CommissionStatus.QUEUE: return 'bg-stone-100 text-stone-600 border-stone-200';
      case CommissionStatus.SKETCH: return 'bg-sky-50 text-sky-600 border-sky-200';
      case CommissionStatus.LINEART: return 'bg-cyan-50 text-cyan-600 border-cyan-200';
      case CommissionStatus.COLOR: return 'bg-purple-50 text-purple-600 border-purple-200';
      case CommissionStatus.RENDER: return 'bg-emerald-50 text-emerald-600 border-emerald-200';
      case CommissionStatus.DONE: return 'bg-[#1a472a] text-white border-[#1a472a]';
      default: return 'bg-stone-100 text-stone-600 border-stone-200';
    }
  };

  const handleNextStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex < STATUS_STEPS.length - 1) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex + 1]);
    }
  };

  const handlePrevStep = () => {
    const currentIndex = STATUS_STEPS.indexOf(commission.status);
    if (currentIndex > 0) {
      onUpdateStatus(commission.id, STATUS_STEPS[currentIndex - 1]);
    }
  };

  return (
    <div className="bg-white border-2 border-stone-100 rounded-3xl p-7 shadow-[0_8px_30px_rgb(0,0,0,0.04)] hover:shadow-[0_8px_30px_rgb(0,0,0,0.08)] transition-all duration-300 group hover:-translate-y-1">

      <div className="flex flex-col justify-between">
        <div>
          <div className="flex justify-between items-start mb-3">
            <div>
              <div className="flex items-center gap-3 mb-2">
                  <span className={`px-3 py-1 rounded-full text-xs font-bold border-2 ${getStatusColor(commission.status)}`}>
                    {commission.status}
                  </span>
                  <p className="text-[#1a472a] text-sm font-bold tracking-wide flex items-center gap-1">
                    <span className="w-1.5 h-1.5 rounded-full bg-[#1a472a]"></span>
                    {commission.clientName}
                  </p>
              </div>
              <h3 className="text-xl font-bold text-stone-700">{commission.title}</h3>
            </div>

            {isAdmin && (
              <div className="flex gap-2">
                  <button 
                    onClick={() => setShowAdminTools(!showAdminTools)}
                    className={`p-2.5 rounded-xl transition-all duration-200 ${showAdminTools ? 'bg-emerald-100 text-emerald-700 rotate-12 scale-110' : 'bg-stone-50 text-stone-400 hover:text-emerald-600 hover:bg-emerald-50 hover:scale-110'}`}
                    title="AI 小幫手"
                  >
                    <Sparkles size={20} />
                  </button>
                  <button 
                    onClick={() => onDelete(commission.id)}
                    className="p-2.5 bg-stone-50 text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all duration-200 hover:scale-110"
                    title="刪除"
                  >
                    <Trash2 size={20} />
                  </button>
              </div>
            )}
          </div>

          <p className="text-stone-500 text-sm leading-relaxed mb-5 font-medium">
            {commission.description}
          </p>

          <div className="flex flex-wrap gap-3 text-xs text-stone-500 font-bold mb-5">
            <span className="flex items-center gap-1.5 bg-stone-50 px-3 py-1.5 rounded-full border border-stone-100">
              <Calendar size={14} className="text-stone-400" /> {commission.dateAdded}
            </span>
            <span className="flex items-center gap-1.5 bg-stone-50 px-3 py-1.5 rounded-full border border-stone-100">
              <DollarSign size={14} className="text-stone-400" /> {commission.price}
            </span>
            <span className="bg-[#1a472a]/5 px-3 py-1.5 rounded-full border border-[#1a472a]/10 text-[#1a472a]">
                {commission.type}
            </span>
          </div>
        </div>

        <div className="mt-2 bg-stone-50/50 rounded-2xl p-4 border border-stone-100">
          <ProgressBar currentStatus={commission.status} />

          {isAdmin && (
            <div className="flex justify-end gap-3 mt-6">
                <button 
                  onClick={handlePrevStep}
                  disabled={commission.status === CommissionStatus.QUEUE}
                  className="flex items-center gap-1.5 px-4 py-2 text-xs font-bold text-stone-500 hover:text-stone-700 disabled:opacity-30 hover:bg-stone-100 rounded-full transition-all"
                >
                  <ChevronLeft size={16} /> 上一步
                </button>
                <button 
                  onClick={handleNextStep}
                  disabled={commission.status === CommissionStatus.DONE}
                  className="flex items-center gap-1.5 px-5 py-2 text-xs font-bold bg-[#1a472a] hover:bg-[#25613a] text-white rounded-full transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-md shadow-[#1a472a]/20 hover:-translate-y-0.5"
                >
                  下一步 <ChevronRight size={16} />
                </button>
            </div>
          )}
        </div>
      </div>

      {isAdmin && showAdminTools && (
         <AdminTools commission={commission} onClose={() => setShowAdminTools(false)} />
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Commission } from '../types';
import { generateClientUpdate, suggestWorkPlan } from '../services/geminiService';
import { Wand2, Send, ListTodo, X } from 'lucide-react';

interface AdminToolsProps {
  commission: Commission;
  onClose: () => void;
}

export const AdminTools: React.FC<AdminToolsProps> = ({ commission, onClose }) => {
  const [generatedText, setGeneratedText] = useState<string>('');
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'email' | 'plan'>('email');

  const handleGenerate = async () => {
    setLoading(true);
    setGeneratedText('');
    let result = '';

    if (activeTab === 'email') {
      result = await generateClientUpdate(commission);
    } else {
      result = await suggestWorkPlan(commission);
    }

    setGeneratedText(result);
    setLoading(false);
  };

  return (
    <div className="mt-6 bg-stone-50 p-5 rounded-3xl border-2 border-stone-200 relative animate-in fade-in slide-in-from-top-4 shadow-inner">
      <button 
        onClick={onClose} 
        className="absolute top-3 right-3 text-stone-400 hover:text-stone-700 bg-white p-1 rounded-full border border-stone-200"
      >
        <X size={14} />
      </button>

      <div className="flex gap-2 mb-4">
        <button
          onClick={() => setActiveTab('email')}
          className={`flex items-center gap-2 px-4 py-2 rounded-full text-xs font-bold transition-all ${
            activeTab === 'email' ? 'bg-[#1a472a] text-white shadow-md' : 'bg-white text-stone-500 hover:bg-stone-100 border border-stone-200'
          }`}
        >
          <Send size={14} /> 草擬回信
        </button>
        <button
          onClick={() => setActiveTab('plan')}
          className={`flex items-center gap-2 px-4 py-2 rounded-full text-xs font-bold transition-all ${
            activeTab === 'plan' ? 'bg-[#1a472a] text-white shadow-md' : 'bg-white text-stone-500 hover:bg-stone-100 border border-stone-200'
          }`}
        >
          <ListTodo size={14} /> 工作建議
        </button>
      </div>

      <div className="min-h-[120px] bg-white rounded-2xl p-4 text-stone-700 text-sm whitespace-pre-wrap border-2 border-stone-200 font-medium leading-relaxed">
        {loading ? (
            <div className="flex flex-col items-center justify-center h-20 gap-2 text-[#1a472a]">
                <Wand2 className="animate-spin" size={24} /> 
                <span className="text-xs font-bold">正在動腦筋...</span>
            </div>
        ) : generatedText ? (
            generatedText
        ) : (
            <div className="flex flex-col items-center justify-center h-20 text-stone-400 gap-1">
                 <Wand2 size={20} className="text-stone-300" />
                 <span className="text-xs">AI 小幫手隨時待命！</span>
            </div>
        )}
      </div>

      <div className="mt-4 flex justify-end">
        <button
            onClick={handleGenerate}
            disabled={loading}
            className="flex items-center gap-2 px-6 py-2.5 bg-gradient-to-r from-[#1a472a] to-emerald-700 hover:from-[#143620] hover:to-emerald-800 text-white rounded-full text-xs font-bold transition-all disabled:opacity-50 shadow-md shadow-emerald-900/10 hover:-translate-y-0.5 active:scale-95"
        >
            <Wand2 size={16} /> {loading ? '思考中...' : '生成內容'}
        </button>
      </div>
    </div>
  );
};

import React from 'react';
import { CommissionStatus } from '../types';
import { STATUS_STEPS } from '../constants';
import { Check, Circle } from 'lucide-react';

interface ProgressBarProps {
  currentStatus: CommissionStatus;
}

export const ProgressBar: React.FC<ProgressBarProps> = ({ currentStatus }) => {
  const currentIndex = STATUS_STEPS.indexOf(currentStatus);

  return (
    <div className="w-full mt-4 mb-2 px-2">
      <div className="flex items-center justify-between relative">
        {/* Background Line */}
        <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-2 bg-stone-200 rounded-full -z-0"></div>

        {/* Active Line (Forest Green) */}
        <div 
            className="absolute left-0 top-1/2 transform -translate-y-1/2 h-2 bg-[#1a472a] rounded-full transition-all duration-500 -z-0"
            style={{ width: `${(currentIndex / (STATUS_STEPS.length - 1)) * 100}%` }}
        ></div>

        {STATUS_STEPS.map((step, index) => {
          const isCompleted = index <= currentIndex;
          const isCurrent = index === currentIndex;

          return (
            <div key={step} className="flex flex-col items-center relative z-10 group cursor-default">
              <div 
                className={`
                  w-8 h-8 rounded-full flex items-center justify-center border-[3px] transition-all duration-300 shadow-sm
                  ${isCompleted ? 'bg-[#1a472a] border-[#1a472a]' : 'bg-white border-stone-200'}
                  ${isCurrent ? 'ring-4 ring-[#1a472a]/20 scale-110' : ''}
                `}
              >
                {isCompleted ? (
                   <Check size={16} className="text-white stroke-[3px]" />
                ) : (
                   <div className="w-2 h-2 rounded-full bg-stone-300"></div>
                )}
              </div>
              <span className={`
                absolute top-9 text-[10px] md:text-xs font-bold tracking-wide transition-colors duration-300 whitespace-nowrap bg-white/80 px-1 rounded-md
                ${isCurrent ? 'text-[#1a472a] -translate-y-0.5' : isCompleted ? 'text-stone-500' : 'text-stone-300'}
              `}>
                {step}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Commission, CommissionStatus, ThemeMode } from './types';
import { MOCK_COMMISSIONS } from './constants';
import { CommissionCard } from './components/CommissionCard';
import { AddCommissionForm } from './components/AddCommissionForm';
import { Search, Palette, Shield, User, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  // State
  const [commissions, setCommissions] = useState<Commission[]>([]);
  const [viewMode, setViewMode] = useState<ThemeMode>('client');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<CommissionStatus | 'All'>('All');
  const [isAdding, setIsAdding] = useState(false);

  // Initialize Data
  useEffect(() => {
    const stored = localStorage.getItem('arttrack_commissions_zh_v1');
    if (stored) {
      setCommissions(JSON.parse(stored));
    } else {
      setCommissions(MOCK_COMMISSIONS);
      localStorage.setItem('arttrack_commissions_zh_v1', JSON.stringify(MOCK_COMMISSIONS));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Persistence
  useEffect(() => {
    if (commissions.length > 0) {
      localStorage.setItem('arttrack_commissions_zh_v1', JSON.stringify(commissions));
    }
  }, [commissions]);

  // Handlers
  const handleUpdateStatus = (id: string, newStatus: CommissionStatus) => {
    setCommissions(prev => prev.map(c => 
      c.id === id ? { ...c, status: newStatus, lastUpdated: new Date().toISOString().split('T')[0] } : c
    ));
  };

  const handleDelete = (id: string) => {
    if (window.confirm('確定要刪除此委託嗎？')) {
      setCommissions(prev => prev.filter(c => c.id !== id));
    }
  };

  const handleAdd = (newCommission: Commission) => {
    setCommissions(prev => [newCommission, ...prev]);
    setIsAdding(false);
  };

  // Filter Logic
  const filteredCommissions = useMemo(() => {
    return commissions.filter(c => {
      const matchesSearch = 
        c.clientName.toLowerCase().includes(searchTerm.toLowerCase()) || 
        c.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.id.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesFilter = statusFilter === 'All' || c.status === statusFilter;

      return matchesSearch && matchesFilter;
    });
  }, [commissions, searchTerm, statusFilter]);

  // Statistics
  const stats = useMemo(() => {
    return {
        queue: commissions.filter(c => c.status === CommissionStatus.QUEUE).length,
        active: commissions.filter(c => c.status !== CommissionStatus.QUEUE && c.status !== CommissionStatus.DONE).length,
        done: commissions.filter(c => c.status === CommissionStatus.DONE).length
    }
  }, [commissions]);

  return (
    <div className="min-h-screen bg-[#fbfaf8] text-stone-700 selection:bg-emerald-200">

      {/* Header - Rounded Bottom */}
      <header className="fixed top-0 w-full z-50 bg-[#1a472a] shadow-lg shadow-[#1a472a]/10 rounded-b-3xl border-b-4 border-[#143620]">
        <div className="max-w-6xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-white/20 rounded-2xl flex items-center justify-center text-white font-bold border-2 border-white/30 text-xl transform -rotate-6 shadow-inner">
                <Sparkles size={20} />
            </div>
            <h1 className="text-xl sm:text-2xl font-bold tracking-wide text-white">
                Commission Tracker
            </h1>
          </div>

          <div className="flex items-center gap-4">
            {/* View Mode Toggle - Capsule Style */}
            <div className="flex bg-[#11301c] rounded-full p-1.5 border border-[#2d5c40]">
               <button 
                onClick={() => setViewMode('client')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-bold transition-all ${viewMode === 'client' ? 'bg-[#fbfaf8] text-[#1a472a] shadow-md' : 'text-emerald-100/60 hover:text-white'}`}
               >
                 <User size={16} /> <span className="hidden sm:inline">委託人</span>
               </button>
               <button 
                onClick={() => setViewMode('admin')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-bold transition-all ${viewMode === 'admin' ? 'bg-[#fbfaf8] text-[#1a472a] shadow-md' : 'text-emerald-100/60 hover:text-white'}`}
               >
                 <Shield size={16} /> <span className="hidden sm:inline">繪師</span>
               </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="pt-32 pb-20 px-4 max-w-5xl mx-auto">

        {/* Intro / Stats */}
        <div className="mb-12 text-center sm:text-left sm:flex justify-between items-end">
            <div className="mb-6 sm:mb-0">
                <h2 className="text-3xl font-bold text-[#1a472a] mb-3 tracking-tight">
                    {viewMode === 'client' ? '委託進度一覽 ✨' : '繪師工作台 🎨'}
                </h2>
                <p className="text-stone-500 max-w-lg font-medium">
                    {viewMode === 'client' 
                        ? '歡迎回來！在下方輸入您的 ID 或暱稱，看看您的委託跑到哪了～' 
                        : '今天也要元氣滿滿的畫圖！這裡可以管理排單和進度喔。'}
                </p>
            </div>
            <div className="flex gap-3 justify-center sm:justify-end text-sm">
                <div className="bg-white border-2 border-stone-200 px-5 py-3 rounded-2xl text-center min-w-[90px] shadow-sm transform hover:-translate-y-1 transition-transform">
                    <div className="text-2xl font-bold text-stone-600">{stats.queue}</div>
                    <div className="text-xs text-stone-400 font-bold">排單中</div>
