import React, { useState } from 'react';
import { Button, TextField, Select, MenuItem, InputLabel, FormControl, Box } from '@mui/material';
import { Commission, CommissionStatus } from '../types';

interface AddCommissionFormProps {
  onAdd: (newCommission: Commission) => void;
}

const AddCommissionForm: React.FC<AddCommissionFormProps> = ({ onAdd }) => {
  const [newCommission, setNewCommission] = useState<Omit<Commission, 'id' | 'artistId'>>({
    clientName: '',
    title: '',
    description: '',
    type: '',
    price: 0,
    status: CommissionStatus.QUEUE,
    dateAdded: new Date().toISOString().split('T')[0],
    lastUpdated: new Date().toISOString().split('T')[0],
    thumbnailUrl: ''
  });

  const handleChange = (event: React.ChangeEvent<HTMLInputElement | { name?: string; value: unknown }>) => {
    const { name, value } = event.target;
    setNewCommission(prev => ({ ...prev, [name]: value }));
  };

  const handleSelectChange = (event: React.ChangeEvent<{ value: unknown }>) => {
    const { name, value } = event.target;
    setNewCommission(prev => ({ ...prev, [name]: value as string }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const commissionToAdd: Commission = {
        ...newCommission,
        id: Math.random().toString(36).substring(2, 15), // Placeholder ID
        artistId: 'Unknown' // Dummy artistId to satisfy type check. Will be overwritten by App.tsx
    };
    onAdd(commissionToAdd);
    setNewCommission({
      clientName: '',
      title: '',
      description: '',
      type: '',
      price: 0,
      status: CommissionStatus.QUEUE,
      dateAdded: new Date().toISOString().split('T')[0],
      lastUpdated: new Date().toISOString().split('T')[0],
      thumbnailUrl: ''
    });
  };

  return (
    <Box component="form" onSubmit={handleSubmit} sx={{ mt: 2, display: 'flex', flexDirection: 'column', gap: 2 }}>
      <TextField label="Client Name" name="clientName" value={newCommission.clientName} onChange={handleChange} required />
      <TextField label="Title" name="title" value={newCommission.title} onChange={handleChange} required />
      <TextField label="Description" name="description" value={newCommission.description} onChange={handleChange} multiline rows={4} required />
      <TextField label="Type" name="type" value={newCommission.type} onChange={handleChange} required />
      <TextField label="Price" name="price" type="number" value={newCommission.price} onChange={handleChange} required />
      <FormControl fullWidth>
        <InputLabel id="status-select-label">Status</InputLabel>
        <Select
          labelId="status-select-label"
          id="status-select"
          name="status"
          value={newCommission.status}
          label="Status"
          onChange={handleSelectChange}
        >
          <MenuItem value={CommissionStatus.QUEUE}>Queue</MenuItem>
          <MenuItem value={CommissionStatus.LINEART}>Lineart</MenuItem>
          <MenuItem value={CommissionStatus.COLORING}>Coloring</MenuItem>
          <MenuItem value={CommissionStatus.REVISIONS}>Revisions</MenuItem>
          <MenuItem value={CommissionStatus.COMPLETED}>Completed</MenuItem>
        </Select>
      </FormControl>
      <TextField label="Thumbnail URL" name="thumbnailUrl" value={newCommission.thumbnailUrl} onChange={handleChange} />
      <Button type="submit" variant="contained">Add Commission</Button>
    </Box>
  );
};

export default AddCommissionForm;
