import React, { useState } from 'react';
import { Commission, CommissionStatus } from '../types';
import { Plus, X, Pencil, Check } from 'lucide-react';

interface AddCommissionFormProps {
  onAdd: (c: Commission) => void;
  onCancel: () => void;
  availableTypes: string[];
  onUpdateTypes: (types: string[]) => void;
}

export const AddCommissionForm: React.FC<AddCommissionFormProps> = ({ 
    onAdd, 
    onCancel, 
    availableTypes, 
    onUpdateTypes 
}) => {
  const [formData, setFormData] = useState<Partial<Commission>>({
    clientName: '',
    title: '',
    description: '',
    type: availableTypes[0] || '插畫',
    price: 0,
    status: CommissionStatus.QUEUE,
  });

  // State for Type Editing Mode
  const [isEditingTypes, setIsEditingTypes] = useState(false);
  const [newTypeInput, setNewTypeInput] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (isEditingTypes) return; // Prevent submission while editing types

    const newCommission: Commission = {
      id: `c-${Date.now()}`,
      artistId: '', // Will be filled by parent
      clientName: formData.clientName || '匿名委託人',
      title: formData.title || '未命名委託',
      description: formData.description || '',
      type: formData.type as string,
      price: Number(formData.price),
      status: formData.status as CommissionStatus,
      dateAdded: new Date().toISOString().split('T')[0],
      lastUpdated: new Date().toISOString().split('T')[0],
      thumbnailUrl: ''
    };
    onAdd(newCommission);
  };

  const handleAddType = () => {
    if (newTypeInput.trim() && !availableTypes.includes(newTypeInput.trim())) {
        const updated = [...availableTypes, newTypeInput.trim()];
        onUpdateTypes(updated);
        setNewTypeInput('');
        // Auto select the new type
        setFormData({...formData, type: newTypeInput.trim()});
    }
  };

  const handleDeleteType = (typeToDelete: string) => {
      const updated = availableTypes.filter(t => t !== typeToDelete);
      onUpdateTypes(updated);
      // If currently selected type was deleted, select the first available
      if (formData.type === typeToDelete && updated.length > 0) {
          setFormData({...formData, type: updated[0]});
      }
  };

  return (
    <div className="bg-white border-2 border-emerald-50 rounded-3xl p-8 mb-10 animate-in fade-in zoom-in-95 duration-200 shadow-xl shadow-emerald-50/50">
      <div className="flex justify-between items-center mb-8 pb-4 border-b-2 border-stone-100">
        <h3 className="text-xl font-bold text-[#1a472a] flex items-center gap-3">
            <div className="bg-emerald-100 p-2 rounded-xl text-[#1a472a]">
                <Plus size={24} /> 
            </div>
            新增委託單
        </h3>
        <button onClick={onCancel} className="bg-stone-100 p-2 rounded-full text-stone-400 hover:text-stone-600 hover:bg-stone-200 transition-colors">
            <X size={20} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-5">
          <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">委託人名稱 (ID)</label>
            <input 
              required
              disabled={isEditingTypes}
              type="text" 
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#1a472a]/10 focus:border-[#1a472a] focus:outline-none font-medium transition-all disabled:opacity-50"
              value={formData.clientName}
              onChange={e => setFormData({...formData, clientName: e.target.value})}
              placeholder="例如: ArtLover99"
            />
          </div>
          <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">委託項目標題</label>
            <input 
              required
              disabled={isEditingTypes}
              type="text" 
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#1a472a]/10 focus:border-[#1a472a] focus:outline-none font-medium transition-all disabled:opacity-50"
              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
              placeholder="例如: 原創角色立繪"
            />
          </div>

           {/* Custom Type Selector Section */}
           <div>
            <div className="flex items-center justify-between mb-2 ml-1">
                <label className="text-xs font-bold text-stone-500">委託類型</label>
                <button 
                    type="button"
                    onClick={() => setIsEditingTypes(!isEditingTypes)}
                    className={`flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full transition-all ${isEditingTypes ? 'bg-[#1a472a] text-white' : 'bg-stone-100 text-stone-400 hover:text-[#1a472a]'}`}
                >
                    {isEditingTypes ? <Check size={10} /> : <Pencil size={10} />}
                    {isEditingTypes ? '完成' : '編輯'}
                </button>
            </div>

            {isEditingTypes ? (
                // EDIT MODE
                <div className="bg-stone-50 border-2 border-dashed border-[#1a472a]/30 rounded-2xl p-3 animate-in fade-in duration-200">
                    <div className="flex flex-wrap gap-2 mb-3">
                        {availableTypes.map(t => (
                            <div key={t} className="flex items-center gap-1 bg-white border border-stone-200 px-2 py-1 rounded-lg text-xs font-bold text-stone-600 shadow-sm">
                                {t}
                                <button 
                                    type="button"
                                    onClick={() => handleDeleteType(t)}
                                    className="text-stone-300 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors"
                                >
                                    <X size={12} />
                                </button>
                            </div>
                        ))}
                    </div>
                    <div className="flex gap-2">
                        <input 
                            type="text"
                            value={newTypeInput}
                            onChange={(e) => setNewTypeInput(e.target.value)}
                            placeholder="新增類型..."
                            className="flex-grow bg-white border border-stone-300 rounded-lg px-2 py-1 text-xs focus:outline-none focus:border-[#1a472a]"
                            onKeyDown={(e) => {
                                if (e.key === 'Enter') {
                                    e.preventDefault();
                                    handleAddType();
                                }
                            }}
                        />
                        <button 
                            type="button"
                            onClick={handleAddType}
                            disabled={!newTypeInput.trim()}
                            className="bg-[#1a472a] text-white rounded-lg px-3 py-1 text-xs font-bold disabled:opacity-50"
                        >
                            新增
                        </button>
                    </div>
                </div>
            ) : (
                // SELECT MODE (Normal)
                <div className="relative">
                    <select 
                    className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#1a472a]/10 focus:border-[#1a472a] focus:outline-none font-medium appearance-none cursor-pointer transition-all"
                    value={formData.type}
                    onChange={e => setFormData({...formData, type: e.target.value})}
                    >
                        {availableTypes.map(t => (
                            <option key={t} value={t}>{t}</option>
                        ))}
                    </select>
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                        ▼
                    </div>
                </div>
            )}
          </div>
        </div>

        <div className="space-y-5">
          <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">價格 (NTD/USD)</label>
            <input 
              type="number" 
              disabled={isEditingTypes}
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#1a472a]/10 focus:border-[#1a472a] focus:outline-none font-medium transition-all disabled:opacity-50"
              value={formData.price}
              onChange={e => setFormData({...formData, price: Number(e.target.value)})}
            />
          </div>
           <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">初始狀態</label>
            <div className="relative">
                <select 
                disabled={isEditingTypes}
                className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#1a472a]/10 focus:border-[#1a472a] focus:outline-none font-medium appearance-none cursor-pointer transition-all disabled:opacity-50"
                value={formData.status}
                onChange={e => setFormData({...formData, status: e.target.value as any})}
                >
                {Object.values(CommissionStatus).map(s => (
                    <option key={s} value={s}>{s}</option>
                ))}
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-stone-400">
                    ▼
                </div>
            </div>
          </div>
          <div>
            <label className="block text-xs font-bold text-stone-500 mb-2 ml-1">詳細需求描述</label>
            <textarea 
              disabled={isEditingTypes}
              className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-4 py-3 text-sm text-stone-700 focus:ring-4 focus:ring-[#1a472a]/10 focus:border-[#1a472a] focus:outline-none h-28 resize-none font-medium transition-all disabled:opacity-50"
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
              placeholder="請輸入委託的詳細內容..."
            />
          </div>
        </div>

        <div className="md:col-span-2 pt-4 flex justify-end border-t border-stone-100 mt-2">
            {isEditingTypes ? (
                <div className="text-xs text-stone-400 font-medium flex items-center">
                    請先完成類型的編輯...
                </div>
            ) : (
                <button 
                    type="submit"
                    className="bg-[#1a472a] hover:bg-[#25613a] text-white font-bold py-3 px-8 rounded-full transition-all shadow-lg shadow-[#1a472a]/20 hover:-translate-y-0.5 active:scale-95 text-sm"
                >
                    建立委託單
                </button>
            )}
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { X, Loader2, AlertCircle } from 'lucide-react';
import { AdminUser, CommissionFormData, CommissionType } from '../types';
import { STEPS } from '../constants';

interface CommissionFormProps {
  currentAdmin: AdminUser;
  onClose: () => void;
  onSubmit: (data: CommissionFormData) => Promise<void>;
}

const CommissionForm: React.FC<CommissionFormProps> = ({ currentAdmin, onClose, onSubmit }) => {
  const [formData, setFormData] = useState<CommissionFormData>({
    clientId: '',
    clientName: '',
    type: 'FLOWING_SAND',
    status: 0,
    note: '',
    price: 0
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Validate inputs
    // Fix: Handle optional clientId with fallback
    const trimmedId = (formData.clientId || '').trim();
    const trimmedName = formData.clientName.trim();

    if (!trimmedId || !trimmedName) {
      setError("請填寫所有必要欄位");
      return;
    }

    setIsSubmitting(true);
    try {
      // Create a timeout promise
      const timeoutPromise = new Promise((_, reject) => 
        setTimeout(() => reject(new Error("請求逾時，請檢查網路連線")), 10000)
      );

      // Race against the actual submission
      await Promise.race([
        onSubmit({
          ...formData,
          clientId: trimmedId,
          clientName: trimmedName
        }),
        timeoutPromise
      ]);
      // If successful, the parent component handles closing
    } catch (err: any) {
      console.error(err);
      setError(err.message || "新增失敗，請檢查網路或稍後再試。");
      setIsSubmitting(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-2xl border-2 border-[#E6DCC3] shadow-xl mb-8 animate-in slide-in-from-top-4 relative">
      <div className="flex justify-between items-center mb-6">
          <h3 className="font-bold text-lg text-[#5C4033]">建立由「{currentAdmin.name}」老師負責的委託</h3>
          <button 
            type="button"
            onClick={onClose} 
            className="text-[#D6C0B3] hover:text-[#A67C52] transition-colors"
            disabled={isSubmitting}
          >
            <X size={20} />
          </button>
      </div>

      {error && (
        <div className="mb-4 p-3 bg-red-50 text-red-500 rounded-xl text-sm font-bold flex items-center gap-2">
          <AlertCircle size={16} />
          {error}
        </div>
      )}

      <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">
        <div className="col-span-1">
          <label className="text-[10px] font-bold text-[#A67C52] block mb-1 uppercase tracking-widest">內部管理 ID (不重複)</label>
          <input 
            required
            disabled={isSubmitting}
            className="w-full border-2 border-[#E6DCC3] bg-[#F9F5F0] focus:bg-white focus:border-[#A67C52] rounded-xl p-2.5 text-sm transition-all outline-none font-medium disabled:opacity-50 text-[#5C4033]"
            placeholder="例如: SN-001"
            value={formData.clientId}
            onChange={e => setFormData({...formData, clientId: e.target.value})}
          />
        </div>
        <div className="col-span-1">
          <label className="text-[10px] font-bold text-[#A67C52] block mb-1 uppercase tracking-widest">客戶暱稱 (查詢用)</label>
          <input 
            required
            disabled={isSubmitting}
            className="w-full border-2 border-[#E6DCC3] bg-[#F9F5F0] focus:bg-white focus:border-[#A67C52] rounded-xl p-2.5 text-sm transition-all outline-none font-medium disabled:opacity-50 text-[#5C4033]"
            placeholder="例如: 沈梨"
            value={formData.clientName}
            onChange={e => setFormData({...formData, clientName: e.target.value})}
          />
        </div>
        <div className="col-span-1">
          <label className="text-[10px] font-bold text-[#A67C52] block mb-1 uppercase tracking-widest">委託類型</label>
          <select 
            disabled={isSubmitting}
            className="w-full border-2 border-[#E6DCC3] bg-[#F9F5F0] focus:bg-white focus:border-[#A67C52] rounded-xl p-2.5 text-sm transition-all outline-none font-medium disabled:opacity-50 text-[#5C4033]"
            value={formData.type}
            onChange={e => {
              const newType = e.target.value as CommissionType;
              setFormData({...formData, type: newType, status: 0});
            }}
          >
            <option value="FLOWING_SAND">流麻</option>
            <option value="SCREENSHOT">截圖</option>
          </select>
        </div>
        <div className="col-span-1">
          <label className="text-[10px] font-bold text-[#A67C52] block mb-1 uppercase tracking-widest">初始階段</label>
          <select 
            disabled={isSubmitting}
            className="w-full border-2 border-[#E6DCC3] bg-[#F9F5F0] focus:bg-white focus:border-[#A67C52] rounded-xl p-2.5 text-sm transition-all outline-none font-medium disabled:opacity-50 text-[#5C4033]"
            value={formData.status}
            onChange={e => setFormData({...formData, status: parseInt(e.target.value)})}
          >
            {STEPS[formData.type].map((s, i) => <option key={i} value={i}>{s.label}</option>)}
          </select>
        </div>

        {/* New Price Field */}
        <div className="col-span-2">
           <label className="text-[10px] font-bold text-[#A67C52] block mb-1 uppercase tracking-widest">委託金額 ($)</label>
           <input 
             type="number"
             disabled={isSubmitting}
             className="w-full border-2 border-[#E6DCC3] bg-[#F9F5F0] focus:bg-white focus:border-[#A67C52] rounded-xl p-2.5 text-sm transition-all outline-none font-medium disabled:opacity-50 text-[#5C4033]"
             placeholder="例如: 1200"
             value={formData.price || ''}
             onChange={e => setFormData({...formData, price: e.target.value ? parseInt(e.target.value) : undefined})}
           />
        </div>

        <div className="col-span-2">
          <label className="text-[10px] font-bold text-[#A67C52] block mb-1 uppercase tracking-widest">備註訊息 (客戶可見)</label>
          <textarea 
            disabled={isSubmitting}
            className="w-full border-2 border-[#E6DCC3] bg-[#F9F5F0] focus:bg-white focus:border-[#A67C52] rounded-xl p-2.5 text-sm transition-all outline-none font-medium disabled:opacity-50 text-[#5C4033]"
            rows={2}
            value={formData.note}
            onChange={e => setFormData({...formData, note: e.target.value})}
          />
        </div>
        <div className="col-span-2 flex justify-end gap-3 mt-2">
          <button 
            type="button" 
            onClick={onClose} 
            className="px-4 py-2 text-sm font-bold text-[#D6C0B3] hover:text-[#A67C52]"
            disabled={isSubmitting}
          >
            取消
          </button>
          <button 
            type="submit" 
            disabled={isSubmitting}
            className="px-5 py-2.5 bg-[#BC4A3C] text-white rounded-xl text-sm font-bold shadow-lg shadow-[#BC4A3C]/20 transition-all active:scale-95 disabled:opacity-70 disabled:active:scale-100 flex items-center gap-2"
          >
            {isSubmitting ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                <span>處理中...</span>
              </>
            ) : (
              <span>儲存委託</span>
            )}
          </button>
        </div>
      </form>
    </div>
  );
};

